{"CoRequisites": [], "CreditType": "", "Credits": "4.00", "CrossListed": "Y", "DepartmentID": "43", "Departments": "EN Applied Mathematics & Statistics", "Description": "An introduction to the basic concepts of linear algebra, matrix theory, and differential equations that are used widely in modern engineering and science. Intended for engineering and science majors whose program does not permit taking both AS.110.201 and AS.110.302.", "Equivalencies": [], "EvaluationUrls": [], "Fees": [], "GradeSystemName": "AE Ugrad Letter", "InstructionMethods": "In-person", "Instructors": [{"HopkinsID": "A77633|A77633"}], "Meetings": [{"Building": "Olin", "DOW": "MWF", "Dates": "08-26-2024 to 12-06-2024", "Format": "Lecture", "Times": "12:00 PM - 12:50 PM"}, {"Building": "Shaffer", "DOW": "T", "Dates": "08-26-2024 to 12-06-2024", "Format": "Discussion Section", "Times": "03:00 PM - 03:50 PM"}], "PosTags": [{"Tag": "ROBO-CMMA"}], "PrereqCoursesCatalogs": [{"Description": "Differential and integral Calculus. Includes analytic geometry, functions, limits, integrals and derivatives, introduction to differential equations, functions of several variables, linear systems, applications for systems of linear differential equations, probability distributions. Applications to the biological and social sciences will be discussed, and the courses are designed to meet the needs of students in these disciplines.  Recommended Course Background: Grade of C- or Better in AS.110.106 or AS.110.108, or a 5 on the AP AB exam.", "Name": "AS.110.107", "SssCoursesId": 3068, "StatusName": "Active", "TermName": "AE Fall 2024", "Title": "Calculus II (For Biological and Social Science)"}, {"Description": "Differential and integral calculus. Includes analytic geometry, functions, limits, integrals and derivatives, polar coordinates, parametric equations, Taylor's theorem and applications, infinite sequences and series.  Some applications to the physical sciences and engineering will be discussed, and the courses are designed to meet the needs of students in these disciplines.  Recommended Course Background: Grade of C- or Better in AS.110.106 or AS.110.108, or a 5 on the AP AB exam.", "Name": "AS.110.109", "SssCoursesId": 3070, "StatusName": "Active", "TermName": "AE Fall 2024", "Title": "Calculus II (For Physical Sciences and Engineering)"}, {"Description": "This is an honors alternative to the Calculus sequences AS.110.106-AS.110.107 or AS.110.108-AS.110.109 and meets the general requirement for both Calculus I and Calculus II (although the credit hours count for only one course). It is a more theoretical treatment of one variable differential and integral calculus and is based on our modern understanding of the real number system as explained by Cantor, Dedekind, and Weierstrass. Students who want to know the "why's and how's" of Calculus will find this course rewarding. Previous background in Calculus is not assumed. Students will learn differential Calculus (derivatives, differentiation, chain rule, optimization, related rates, etc), the theory of integration, the fundamental theorem(s) of Calculus, applications of integration, and Taylor series. Students should have a strong ability to learn mathematics quickly and on a higher level than that of the regular Calculus sequences.", "Name": "AS.110.113", "SssCoursesId": 3074, "StatusName": "Active", "TermName": "AE Fall 2024", "Title": "Honors Single Variable Calculus"}], "Prerequisites": [{"Description": "AS.110.107 OR AS.110.109 OR AS.110.113", "Expression": "AS.110.107[C]^OR^AS.110.109[C]^OR^AS.110.113[C]", "IsNegative": "N"}], "Restrictions": [{"Description": "", "RestrictionName": "UGrad Biomedical Engineering majors"}], "SampleSyllabus": "", "SectionCoReqNotes": "", "SectionCoRequisites": "", "StandardSyllabusLink": "", "TextbookInformations": [{"AttributeValue": "Barnes & Noble", "BookstoreID": "", "ClassStartDate": "20240826", "CourseName": "EN.553.291", "CourseNumber": "", "Department": "", "IdrGroupTerm": "F24", "Location": "Homewood Campus", "MbsGroupDesignator": "", "MbsSiteCode": "", "Name": "02", "SectionNumber": "", "Term": "", "ZonesName": "ASEN - UGrad"}], "WebNotes": "Section restricted to BME students.

This course is supported by the PILOT Program and the Learning Den
"}

